(function() {
  const SELECTORS = [
    "#onetrust-accept-btn-handler",
    "#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll",
    "#CybotCookiebotDialogBodyButtonDecline",
    ".cc-accept",
    ".cc-dismiss",
    "#accept-cookies",
    ".cookie-accept",
    '[data-consent="accept"]',
    "#cookie-accept-btn",
    ".accept-cookies-button",
    ".js-accept-cookies",
    '[aria-label="Accept cookies"]',
    '[aria-label="Accept all cookies"]',
    ".cookie-consent-accept",
    ".cookie-notice__accept",
    "#gdpr-cookie-accept",
    ".gdpr-accept",
    "#cookiescript_accept",
    ".cmplz-accept",
    "#hs-eu-confirmation-button",
    ".fc-cta-consent",
    '.qc-cmp2-summary-buttons button[mode="primary"]',
    "#didomi-notice-agree-button",
    ".sp_choice_type_11",
    '[data-testid="cookie-policy-manage-dialog-btn-accept"]',
    "#consent_prompt_submit",
    ".cn-accept",
    "#ez-accept-all",
    ".cli-plugin-button",
    ".js-cookie-banner-accept",
    ".js-cookie-banner-reject",
    ".govuk-cookie-banner .govuk-button",
    ".cmpboxbtnyes",
    "#cmpwelcomebtnyes a",
    ".cmpboxbtnno",
    "#cmpwelcomebtnno a",
    ".cmpboxbtnsave",
    "#cmpbntyestxt",
    "#cmpbntnotxt",
    ".iubenda-cs-accept-btn",
    "#truste-consent-button",
    ".evidon-banner-acceptbutton",
    "#ensNotifyBanner .accept",
    ".cc-compliance .cc-btn",
    ".cc-nb-okagree",
    ".cc-nb-reject",
    ".cc-cp-foot-accept",
    ".cc-cp-foot-save",
    '[data-cc-event="click:dismiss"]',
    '[data-cc-event="click:accept"]',
    '[aria-label="cookieconsent"] .cc-btn'
  ];

  const TEXT_PATTERNS = /^(accept(\s+(all|analytics))?\s*(cookies)?|reject(\s+(all|analytics))?\s*(cookies)?|agree|allow(\s+all)?|got it|i agree|okay|ok|consent|allow cookies|accept cookies|accept all cookies|dismiss|close|verstanden|akzeptieren|alle akzeptieren|tout accepter|accepter|accepteer alles|aceptar todo|aceptar)$/i;

  const COOKIE_HINTS = ['cookie', 'consent', 'banner', 'gdpr', 'cmp', 'privacy', 'notice'];

  function collectShadowRoots(root, results) {
    const dominated = root === document ? document.body : root;
    if (!dominated) return;
    const walker = document.createTreeWalker(dominated, NodeFilter.SHOW_ELEMENT);
    let node = walker.currentNode;
    while (node) {
      if (node.shadowRoot) {
        results.push(node.shadowRoot);
        collectShadowRoots(node.shadowRoot, results);
      }
      node = walker.nextNode();
    }
  }

  function queryDeep(selector) {
    const found = document.querySelector(selector);
    if (found) return found;
    const shadows = [];
    collectShadowRoots(document, shadows);
    for (const shadow of shadows) {
      const el = shadow.querySelector(selector);
      if (el) return el;
    }
    return null;
  }

  function queryAllDeep(selector) {
    const results = Array.from(document.querySelectorAll(selector));
    const shadows = [];
    collectShadowRoots(document, shadows);
    for (const shadow of shadows) {
      try {
        results.push(...shadow.querySelectorAll(selector));
      } catch (_) {}
    }
    return results;
  }

  function isVisible(el) {
    if (!(el instanceof HTMLElement)) return false;
    if (el.offsetWidth === 0 && el.offsetHeight === 0) return false;
    if (el.offsetParent !== null) return true;
    const style = getComputedStyle(el);
    return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
  }

  function isCookieRelated(el) {
    const id = (el.id || '').toLowerCase();
    const cls = (el.className || '').toLowerCase();
    return COOKIE_HINTS.some(function(h) { return id.includes(h) || cls.includes(h); });
  }

  function clickBySelectorMatch() {
    for (const sel of SELECTORS) {
      const el = queryDeep(sel);
      if (el && isVisible(el)) {
        el.click();
        return true;
      }
    }
    return false;
  }

  function clickByTextMatch() {
    const btnSelector = 'button, a[role="button"], [role="button"]';
    const candidates = queryAllDeep(btnSelector);
    for (const el of candidates) {
      if (!isVisible(el)) continue;
      if (!isCookieRelated(el) && !isCookieRelated(el.closest('[class], [id]') || el)) continue;
      const text = (el.textContent || '').trim();
      if (text.length > 0 && text.length < 60 && TEXT_PATTERNS.test(text)) {
        el.click();
        return true;
      }
    }
    return false;
  }

  function dismiss() {
    return clickBySelectorMatch() || clickByTextMatch();
  }

  if (dismiss()) return;

  let pending = 0;
  const observer = new MutationObserver(function() {
    if (pending) return;
    pending = requestAnimationFrame(function() {
      pending = 0;
      if (dismiss()) observer.disconnect();
    });
  });
  observer.observe(document.body, { childList: true, subtree: true });
  setTimeout(function() { observer.disconnect(); }, 10000);
})();
